67	        }
68	
69	        // 2. Max 2 reschedules
70	        if (appointment.getRescheduleCount() >= 2) {
71	            throw new BusinessException(4011, "Exceeded maximum of 2 reschedules.");
72	        }
73	
74	        // 3. Time validation
75	        validateTimeRange(request.getStartTime(), request.getEndTime());
76	
77	        // 4. Overlapping conflict
78	        boolean conflict = appointmentRepository.existsConflict(
79	                appointment.getStaffId(),
80	                appointment.getResourceId(),
81	                request.getStartTime(),
82	                request.getEndTime(),
83	                "CANCELLED"
84	        );
85	        if (conflict) {
86	            throw new BusinessException(4006, "Appointment time conflicts with existing schedule.");
87	        }
88	
89	        appointment.setStartTime(request.getStartTime());
90	        appointment.setEndTime(request.getEndTime());
91	        appointment.setRescheduleCount(appointment.getRescheduleCount() + 1);
92	        appointment.setStatus("RESCHEDULED");
93	
94	        return appointmentRepository.save(appointment);
95	    }
96	
97	    public void cancel(Long id) {
98	        Appointment appointment = getById(id);
99	        LocalDateTime now = LocalDateTime.now();
100	        
101	        if (ChronoUnit.HOURS.between(now, appointment.getStartTime()) < 24) {
102	            appointment.setPenalty(new BigDecimal("50.00")); // 50 RMB penalty
103	        }
104	        
105	        appointment.setStatus("CANCELLED");
106	        appointmentRepository.save(appointment);
107	    }
108	
109	    @Transactional(Transactional.TxType.SUPPORTS)
110	    public Appointment getById(Long id) {
111	        return appointmentRepository.findById(id)
112	                .orElseThrow(() -> new BusinessException(4042, "Appointment not found."));
113	    }
114	
115	    @Transactional(Transactional.TxType.SUPPORTS)
116	    public List<Appointment> list() {
117	        return appointmentRepository.findAll(Sort.by(Sort.Direction.DESC, "startTime"));
118	    }
119	
120	    private void validateTimeRange(LocalDateTime startTime, LocalDateTime endTime) {
121	        if (startTime == null || endTime == null || !endTime.isAfter(startTime)) {
122	            throw new BusinessException(4007, "endTime must be after startTime.");
123	        }
124	    }
125	
126	    private String resolveNumber(String inputNumber) {
127	        if (StringUtils.hasText(inputNumber)) {
128	            String number = inputNumber.trim().toUpperCase();
129	            if (appointmentRepository.existsByNumber(number)) {
130	                throw new BusinessException(4008, "Appointment number already exists.");
131	            }
132	            return number;
133	        }
134	
135	        for (int attempt = 0; attempt < 8; attempt++) {
136	            String generated = "APPT-" + LocalDateTime.now().format(NUMBER_FORMATTER)
137	                    + "-" + ThreadLocalRandom.current().nextInt(1000, 10000);
138	            if (!appointmentRepository.existsByNumber(generated)) {
139	                return generated;
140	            }
141	        }
142	        throw new BusinessException(4009, "Unable to generate unique appointment number.");
143	    }
144	
145	    private String normalizeOrDefault(String value, String defaultValue) {
146	        return StringUtils.hasText(value) ? value.trim().toUpperCase() : defaultValue;
147	    }
