1	package com.anju.converter;
2	
3	import jakarta.persistence.AttributeConverter;
4	import jakarta.persistence.Converter;
5	
6	import javax.crypto.Cipher;
7	import javax.crypto.spec.GCMParameterSpec;
8	import javax.crypto.spec.SecretKeySpec;
9	import java.nio.ByteBuffer;
10	import java.nio.charset.StandardCharsets;
11	import java.security.GeneralSecurityException;
12	import java.security.MessageDigest;
13	import java.security.SecureRandom;
14	import java.util.Arrays;
15	import java.util.Base64;
16	
17	@Converter
18	public class CryptoConverter implements AttributeConverter<String, String> {
19	
20	    private static final String AES_ALGORITHM = "AES";
21	    private static final String AES_TRANSFORMATION = "AES/GCM/NoPadding";
22	    private static final int GCM_TAG_BIT_LENGTH = 128;
23	    private static final int GCM_IV_LENGTH = 12;
24	    private static final SecureRandom SECURE_RANDOM = new SecureRandom();
25	    private static final SecretKeySpec SECRET_KEY = buildSecretKey();
26	
27	    @Override
28	    public String convertToDatabaseColumn(String attribute) {
29	        if (attribute == null || attribute.isBlank()) {
30	            return attribute;
31	        }
32	        try {
33	            byte[] iv = new byte[GCM_IV_LENGTH];
34	            SECURE_RANDOM.nextBytes(iv);
35	
36	            Cipher cipher = Cipher.getInstance(AES_TRANSFORMATION);
37	            cipher.init(Cipher.ENCRYPT_MODE, SECRET_KEY, new GCMParameterSpec(GCM_TAG_BIT_LENGTH, iv));
38	            byte[] encrypted = cipher.doFinal(attribute.getBytes(StandardCharsets.UTF_8));
39	
40	            ByteBuffer payload = ByteBuffer.allocate(iv.length + encrypted.length);
41	            payload.put(iv);
42	            payload.put(encrypted);
43	            return Base64.getEncoder().encodeToString(payload.array());
44	        } catch (GeneralSecurityException ex) {
45	            throw new IllegalStateException("Failed to encrypt sensitive field.");
46	        }
47	    }
48	
49	    @Override
50	    public String convertToEntityAttribute(String dbData) {
51	        if (dbData == null || dbData.isBlank()) {
52	            return dbData;
53	        }
54	        try {
55	            byte[] encryptedPayload = Base64.getDecoder().decode(dbData);
56	            ByteBuffer payload = ByteBuffer.wrap(encryptedPayload);
57	
58	            byte[] iv = new byte[GCM_IV_LENGTH];
59	            payload.get(iv);
60	
61	            byte[] encrypted = new byte[payload.remaining()];
62	            payload.get(encrypted);
63	
64	            Cipher cipher = Cipher.getInstance(AES_TRANSFORMATION);
65	            cipher.init(Cipher.DECRYPT_MODE, SECRET_KEY, new GCMParameterSpec(GCM_TAG_BIT_LENGTH, iv));
66	            byte[] plain = cipher.doFinal(encrypted);
67	            return new String(plain, StandardCharsets.UTF_8);
68	        } catch (Exception ex) {
69	            throw new IllegalStateException("Failed to decrypt sensitive field.");
70	        }
71	    }
72	
73	    private static SecretKeySpec buildSecretKey() {
74	        String rawKey = System.getenv("ANJU_CRYPTO_KEY");
75	        if (rawKey == null || rawKey.isBlank()) {
76	            rawKey = System.getProperty("anju.crypto.key", "change-this-in-production");
77	        }
78	
79	        try {
80	            MessageDigest digest = MessageDigest.getInstance("SHA-256");
81	            byte[] key = Arrays.copyOf(digest.digest(rawKey.getBytes(StandardCharsets.UTF_8)), 16);
82	            return new SecretKeySpec(key, AES_ALGORITHM);
83	        } catch (Exception ex) {
84	            throw new IllegalStateException("Unable to initialize encryption key.");
85	        }
86	    }
87	}
