26	    public Property create(CreatePropertyRequest request) {
27	        validateDateRange(request.getStartDate(), request.getEndDate());
28	        if (propertyRepository.existsByCode(request.getCode())) {
29	            throw new BusinessException(4003, "Property code already exists.");
30	        }
31	
32	        Property property = new Property();
33	        property.setCode(normalize(request.getCode()));
34	        property.setStatus(normalizeOrDefault(request.getStatus(), "DELISTED"));
35	        property.setRent(request.getRent());
36	        property.setDeposit(request.getDeposit());
37	        property.setStartDate(request.getStartDate());
38	        property.setEndDate(request.getEndDate());
39	        property.setComplianceStatus(normalizeOrDefault(request.getComplianceStatus(), "PENDING"));
40	        return propertyRepository.save(property);
41	    }
42	
43	    @Transactional(Transactional.TxType.SUPPORTS)
44	    public Property getById(Long id) {
45	        return propertyRepository.findById(id)
46	                .orElseThrow(() -> new BusinessException(4040, "Property not found."));
47	    }
48	
49	    @Transactional(Transactional.TxType.SUPPORTS)
50	    public List<Property> list(String status, String complianceStatus) {
51	        Specification<Property> specification = Specification.where(null);
52	        if (StringUtils.hasText(status)) {
53	            String normalizedStatus = normalize(status);
54	            specification = specification.and((root, query, cb) -> cb.equal(root.get("status"), normalizedStatus));
55	        }
56	        if (StringUtils.hasText(complianceStatus)) {
57	            String normalizedComplianceStatus = normalize(complianceStatus);
58	            specification = specification.and((root, query, cb) ->
59	                    cb.equal(root.get("complianceStatus"), normalizedComplianceStatus));
60	        }
61	        return propertyRepository.findAll(specification, Sort.by(Sort.Direction.DESC, "createdAt"));
62	    }
63	
64	    public Property update(Long id, UpdatePropertyRequest request) {
65	        Property property = getById(id);
66	
67	        if (StringUtils.hasText(request.getCode())) {
68	            String newCode = normalize(request.getCode());
69	            if (propertyRepository.existsByCodeAndIdNot(newCode, id)) {
70	                throw new BusinessException(4004, "Property code already exists.");
71	            }
72	            property.setCode(newCode);
73	        }
74	        if (request.getRent() != null) {
75	            property.setRent(request.getRent());
76	        }
77	        if (request.getDeposit() != null) {
78	            property.setDeposit(request.getDeposit());
79	        }
80	        if (StringUtils.hasText(request.getStatus())) {
81	            property.setStatus(normalize(request.getStatus()));
82	        }
83	        if (request.getStartDate() != null) {
84	            property.setStartDate(request.getStartDate());
85	        }
86	        if (request.getEndDate() != null) {
87	            property.setEndDate(request.getEndDate());
88	        }
89	        if (StringUtils.hasText(request.getComplianceStatus())) {
90	            property.setComplianceStatus(normalize(request.getComplianceStatus()));
91	        }
92	
93	        validateDateRange(property.getStartDate(), property.getEndDate());
94	        return propertyRepository.save(property);
95	    }
