19	@Service
20	@Transactional
21	public class AppointmentService {
22	
23	    private static final DateTimeFormatter NUMBER_FORMATTER = DateTimeFormatter.ofPattern("yyyyMMddHHmmss");
24	    private final AppointmentRepository appointmentRepository;
25	    private final PropertyRepository propertyRepository;
26	
27	    public AppointmentService(AppointmentRepository appointmentRepository, PropertyRepository propertyRepository) {
28	        this.appointmentRepository = appointmentRepository;
29	        this.propertyRepository = propertyRepository;
30	    }
31	
32	    public Appointment create(CreateAppointmentRequest request) {
33	        validateTimeRange(request.getStartTime(), request.getEndTime());
34	        if (!propertyRepository.existsById(request.getResourceId())) {
35	            throw new BusinessException(4041, "Resource property does not exist.");
36	        }
37	        boolean conflict = appointmentRepository.existsConflict(
38	                request.getStaffId(),
39	                request.getResourceId(),
40	                request.getStartTime(),
41	                request.getEndTime(),
42	                "CANCELLED"
43	        );
44	        if (conflict) {
45	            throw new BusinessException(4006, "Appointment time conflicts with existing schedule.");
46	        }
47	
48	        Appointment appointment = new Appointment();
49	        appointment.setNumber(resolveNumber(request.getNumber()));
50	        appointment.setStaffId(request.getStaffId());
51	        appointment.setResourceId(request.getResourceId());
52	        appointment.setStartTime(request.getStartTime());
53	        appointment.setEndTime(request.getEndTime());
54	        appointment.setStatus(normalizeOrDefault(request.getStatus(), "PENDING"));
55	        appointment.setPenalty(request.getPenalty() == null ? BigDecimal.ZERO : request.getPenalty());
56	        appointment.setRescheduleCount(request.getRescheduleCount() == null ? 0 : request.getRescheduleCount());
57	        return appointmentRepository.save(appointment);
58	    }
59	
60	    public Appointment reschedule(Long id, RescheduleAppointmentRequest request) {
61	        Appointment appointment = getById(id);
62	        
63	        // 1. Must be at least 24 hours in advance
64	        LocalDateTime now = LocalDateTime.now();
65	        if (ChronoUnit.HOURS.between(now, appointment.getStartTime()) < 24) {
66	            throw new BusinessException(4010, "Cannot reschedule less than 24 hours before appointment.");
67	        }
68	
69	        // 2. Max 2 reschedules
70	        if (appointment.getRescheduleCount() >= 2) {
71	            throw new BusinessException(4011, "Exceeded maximum of 2 reschedules.");
72	        }
73	
74	        // 3. Time validation
75	        validateTimeRange(request.getStartTime(), request.getEndTime());
76	
77	        // 4. Overlapping conflict
78	        boolean conflict = appointmentRepository.existsConflict(
79	                appointment.getStaffId(),
80	                appointment.getResourceId(),
81	                request.getStartTime(),
82	                request.getEndTime(),
83	                "CANCELLED"
84	        );
85	        if (conflict) {
86	            throw new BusinessException(4006, "Appointment time conflicts with existing schedule.");
87	        }
88	
89	        appointment.setStartTime(request.getStartTime());
90	        appointment.setEndTime(request.getEndTime());
91	        appointment.setRescheduleCount(appointment.getRescheduleCount() + 1);
92	        appointment.setStatus("RESCHEDULED");
93	
94	        return appointmentRepository.save(appointment);
95	    }
96	
97	    public void cancel(Long id) {
98	        Appointment appointment = getById(id);
99	        LocalDateTime now = LocalDateTime.now();
100	        
101	        if (ChronoUnit.HOURS.between(now, appointment.getStartTime()) < 24) {
102	            BigDecimal orderAmount = new BigDecimal("500.00"); // Standard fallback for calculation
103	            BigDecimal penaltyPercentage = orderAmount.multiply(new BigDecimal("0.10"));
104	            BigDecimal maxPenalty = new BigDecimal("50.00");
105	            appointment.setPenalty(penaltyPercentage.min(maxPenalty));
106	        }
107	        
108	        appointment.setStatus("CANCELLED");
109	        appointmentRepository.save(appointment);
110	    }
111	
112	    @org.springframework.scheduling.annotation.Scheduled(fixedRate = 60000)
113	    public void autoReleaseUnconfirmedAppointments() {
114	        LocalDateTime threshold = LocalDateTime.now().minusMinutes(15);
115	        List<Appointment> pending = appointmentRepository.findByStatusAndCreatedAtBefore("PENDING", threshold);
116	        for (Appointment appt : pending) {
117	            appt.setStatus("RELEASED");
118	            appointmentRepository.save(appt);
119	        }
120	    }
121	
122	    @Transactional(Transactional.TxType.SUPPORTS)
123	    public Appointment getById(Long id) {
124	        return appointmentRepository.findById(id)
125	                .orElseThrow(() -> new BusinessException(4042, "Appointment not found."));
126	    }
127	
128	    @Transactional(Transactional.TxType.SUPPORTS)
129	    public List<Appointment> list() {
130	        return appointmentRepository.findAll(Sort.by(Sort.Direction.DESC, "startTime"));
131	    }
132	
133	    private void validateTimeRange(LocalDateTime startTime, LocalDateTime endTime) {
134	        if (startTime == null || endTime == null || !endTime.isAfter(startTime)) {
135	            throw new BusinessException(4007, "endTime must be after startTime.");
136	        }
137	        long diffMinutes = ChronoUnit.MINUTES.between(startTime, endTime);
138	        if (diffMinutes != 15 && diffMinutes != 30 && diffMinutes != 60 && diffMinutes != 90) {
139	            throw new BusinessException(4012, "Service duration must be 15, 30, 60, or 90 minutes.");
140	        }
141	    }
142	
143	    private String resolveNumber(String inputNumber) {
144	        if (StringUtils.hasText(inputNumber)) {
145	            String number = inputNumber.trim().toUpperCase();
146	            if (appointmentRepository.existsByNumber(number)) {
147	                throw new BusinessException(4008, "Appointment number already exists.");
148	            }
149	            return number;
150	        }
151	
152	        for (int attempt = 0; attempt < 8; attempt++) {
153	            String generated = "APPT-" + LocalDateTime.now().format(NUMBER_FORMATTER)
154	                    + "-" + ThreadLocalRandom.current().nextInt(1000, 10000);
155	            if (!appointmentRepository.existsByNumber(generated)) {
156	                return generated;
157	            }
158	        }
159	        throw new BusinessException(4009, "Unable to generate unique appointment number.");
160	    }
161	
162	    private String normalizeOrDefault(String value, String defaultValue) {
163	        return StringUtils.hasText(value) ? value.trim().toUpperCase() : defaultValue;
164	    }
165	}
