3	import com.anju.common.BusinessException;
4	import com.anju.common.Result;
5	import jakarta.validation.ConstraintViolationException;
6	import org.slf4j.Logger;
7	import org.slf4j.LoggerFactory;
8	import org.springframework.http.HttpStatus;
9	import org.springframework.http.ResponseEntity;
10	import org.springframework.validation.FieldError;
11	import org.springframework.web.bind.MethodArgumentNotValidException;
12	import org.springframework.web.bind.annotation.ExceptionHandler;
13	import org.springframework.web.bind.annotation.RestControllerAdvice;
14	
15	import java.util.stream.Collectors;
16	
17	@RestControllerAdvice
18	public class GlobalExceptionHandler {
19	
20	    private static final Logger log = LoggerFactory.getLogger(GlobalExceptionHandler.class);
21	
22	    @ExceptionHandler(BusinessException.class)
23	    public ResponseEntity<Result<Void>> handleBusinessException(BusinessException ex) {
24	        Result<Void> result = Result.fail(ex.getCode(), ex.getMessage());
25	        return ResponseEntity.status(HttpStatus.BAD_REQUEST).body(result);
26	    }
27	
28	    @ExceptionHandler(MethodArgumentNotValidException.class)
29	    public ResponseEntity<Result<Void>> handleMethodArgumentNotValidException(MethodArgumentNotValidException ex) {
30	        String message = ex.getBindingResult()
31	                .getFieldErrors()
32	                .stream()
33	                .map(this::formatFieldError)
34	                .collect(Collectors.joining("; "));
35	
36	        if (message.isBlank()) {
37	            message = "Request parameter validation failed.";
38	        }
39	        Result<Void> result = Result.fail(4001, message);
40	        return ResponseEntity.status(HttpStatus.BAD_REQUEST).body(result);
41	    }
42	
43	    @ExceptionHandler(ConstraintViolationException.class)
44	    public ResponseEntity<Result<Void>> handleConstraintViolationException(ConstraintViolationException ex) {
45	        Result<Void> result = Result.fail(4002, "Request parameter validation failed.");
46	        return ResponseEntity.status(HttpStatus.BAD_REQUEST).body(result);
47	    }
48	
49	    @ExceptionHandler(Exception.class)
50	    public ResponseEntity<Result<Void>> handleException(Exception ex) {
51	        log.error("Unhandled system exception", ex);
52	        Result<Void> result = Result.fail(5000, "System is busy, please try again later.");
53	        return ResponseEntity.status(HttpStatus.OK).body(result);
54	    }
55	
56	    private String formatFieldError(FieldError fieldError) {
57	        String defaultMessage = fieldError.getDefaultMessage();
58	        if (defaultMessage == null || defaultMessage.isBlank()) {
59	            return fieldError.getField() + " is invalid";
60	        }
61	        return fieldError.getField() + ": " + defaultMessage;
62	    }
63	}
