1	package com.anju.domain.auth;
2	
3	import com.anju.common.BusinessException;
4	import com.anju.domain.auth.dto.LoginRequest;
5	import com.anju.domain.auth.dto.RegisterRequest;
6	import jakarta.transaction.Transactional;
7	import org.springframework.security.authentication.AuthenticationManager;
8	import org.springframework.security.authentication.UsernamePasswordAuthenticationToken;
9	import org.springframework.security.crypto.password.PasswordEncoder;
10	import org.springframework.stereotype.Service;
11	import org.springframework.util.StringUtils;
12	
13	import java.time.LocalDateTime;
14	import java.util.regex.Pattern;
15	
16	@Service
17	@Transactional
18	public class AuthService {
19	
20	    private static final Pattern PASSWORD_POLICY = Pattern.compile("^(?=.*[A-Za-z])(?=.*\\d).{8,}$");
21	    private final UserRepository userRepository;
22	    private final PasswordEncoder passwordEncoder;
23	    private final AuthenticationManager authenticationManager;
24	
25	    public AuthService(UserRepository userRepository,
26	                       PasswordEncoder passwordEncoder,
27	                       AuthenticationManager authenticationManager) {
28	        this.userRepository = userRepository;
29	        this.passwordEncoder = passwordEncoder;
30	        this.authenticationManager = authenticationManager;
31	    }
32	
33	    public User register(RegisterRequest request) {
34	        if (userRepository.existsByUsername(request.getUsername())) {
35	            throw new BusinessException(4090, "Username already exists.");
36	        }
37	        validatePassword(request.getPassword());
38	        if (StringUtils.hasText(request.getSecondaryPassword())) {
39	            validatePassword(request.getSecondaryPassword());
40	        }
41	
42	        User user = new User();
43	        user.setUsername(request.getUsername().trim());
44	        user.setPassword(passwordEncoder.encode(request.getPassword()));
45	        user.setDisplayName(request.getDisplayName().trim());
46	        user.setEmail(request.getEmail());
47	        user.setPhone(request.getPhone());
48	        user.setRole(StringUtils.hasText(request.getRole()) ? request.getRole().trim().toUpperCase() : "STAFF");
49	        user.setStatus(1);
50	        if (StringUtils.hasText(request.getSecondaryPassword())) {
51	            user.setSecondaryPassword(passwordEncoder.encode(request.getSecondaryPassword()));
52	        }
53	        return userRepository.save(user);
54	    }
55	
56	    public User login(LoginRequest request) {
57	        authenticationManager.authenticate(
58	                new UsernamePasswordAuthenticationToken(request.getUsername(), request.getPassword())
59	        );
60	
61	        User user = userRepository.findByUsername(request.getUsername())
62	                .orElseThrow(() -> new BusinessException(4044, "User not found."));
63	        user.setLastLoginAt(LocalDateTime.now());
64	        return userRepository.save(user);
65	    }
66	
67	    public void verifySecondaryPassword(String username, String secondaryPassword) {
68	        User user = userRepository.findByUsername(username)
69	                .orElseThrow(() -> new BusinessException(4044, "User not found."));
70	        if (!StringUtils.hasText(user.getSecondaryPassword())) {
71	            throw new BusinessException(4032, "Secondary password is not configured for this account.");
72	        }
73	        if (!passwordEncoder.matches(secondaryPassword, user.getSecondaryPassword())) {
74	            throw new BusinessException(4033, "Invalid secondary password.");
75	        }
76	    }
77	
78	    private void validatePassword(String password) {
79	        if (!PASSWORD_POLICY.matcher(password).matches()) {
80	            throw new BusinessException(4003, "Password must be at least 8 chars and contain letters and numbers.");
81	        }
82	    }
83	}
