42	    public Object aroundAuditableMethod(ProceedingJoinPoint joinPoint, Auditable auditable) throws Throwable {
43	        SysAuditLog auditLog = new SysAuditLog();
44	        auditLog.setTraceId(MDC.get("traceId"));
45	        auditLog.setUsername(resolveOperator(auditable));
46	        auditLog.setModule(auditable.module());
47	        auditLog.setAction(auditable.action());
48	        auditLog.setCreatedAt(LocalDateTime.now());
49	        auditLog.setRequestPayload(serializeArguments(joinPoint.getArgs()));
50	        enrichRequestInfo(auditLog);
51	
52	        try {
53	            Object result = joinPoint.proceed();
54	            auditLog.setSuccess(Boolean.TRUE);
55	            auditLog.setResponsePayload(serialize(result));
56	            persistAuditLog(auditLog);
57	            return result;
58	        } catch (Throwable ex) {
59	            auditLog.setSuccess(Boolean.FALSE);
60	            auditLog.setErrorMessage(sanitizeErrorMessage(ex));
61	            persistAuditLog(auditLog);
62	            throw ex;
63	        }
64	    }
65	
66	    private void enrichRequestInfo(SysAuditLog auditLog) {
67	        ServletRequestAttributes attrs = (ServletRequestAttributes) RequestContextHolder.getRequestAttributes();
68	        if (attrs == null) {
69	            return;
70	        }
71	        HttpServletRequest request = attrs.getRequest();
72	        auditLog.setHttpMethod(request.getMethod());
73	        auditLog.setEndpoint(request.getRequestURI());
74	        auditLog.setIpAddress(resolveClientIp(request));
75	        auditLog.setUserAgent(request.getHeader("User-Agent"));
76	    }
77	
78	    private String resolveOperator(Auditable auditable) {
79	        if (StringUtils.hasText(auditable.operator())) {
80	            return auditable.operator();
81	        }
82	        Authentication authentication = SecurityContextHolder.getContext().getAuthentication();
83	        if (authentication != null && authentication.isAuthenticated() && StringUtils.hasText(authentication.getName())) {
84	            return authentication.getName();
85	        }
86	        return "anonymous";
87	    }
88	
89	    private String resolveClientIp(HttpServletRequest request) {
90	        String forwardedFor = request.getHeader("X-Forwarded-For");
91	        if (StringUtils.hasText(forwardedFor)) {
92	            String[] forwardedParts = forwardedFor.split(",");
93	            if (forwardedParts.length > 0) {
94	                return forwardedParts[0].trim();
95	            }
96	        }
97	        String realIp = request.getHeader("X-Real-IP");
98	        if (StringUtils.hasText(realIp)) {
99	            return realIp;
100	        }
101	        return request.getRemoteAddr();
102	    }
103	
104	    private String sanitizeErrorMessage(Throwable ex) {
105	        String message = ex.getMessage();
106	        if (!StringUtils.hasText(message)) {
107	            return "Unexpected error";
108	        }
109	        if (message.length() > 1000) {
110	            return message.substring(0, 1000);
111	        }
112	        return message;
113	    }
114	
115	    private String serializeArguments(Object[] args) {
116	        List<Object> serializableArgs = new ArrayList<>();
117	        if (args != null) {
118	            for (Object arg : args) {
119	                if (isSerializableArgument(arg)) {
120	                    serializableArgs.add(arg);
121	                }
122	            }
123	        }
124	        return serialize(serializableArgs);
125	    }
126	
127	    private boolean isSerializableArgument(Object arg) {
128	        return !(arg instanceof ServletRequest)
129	                && !(arg instanceof ServletResponse)
130	                && !(arg instanceof MultipartFile)
131	                && !(arg instanceof BindingResult);
132	    }
133	
134	    private String serialize(Object value) {
135	        if (value == null) {
136	            return null;
137	        }
138	        try {
139	            return objectMapper.writeValueAsString(value);
140	        } catch (JsonProcessingException ex) {
141	            return "\"<unserializable>\"";
142	        }
143	    }
144	
145	    private void persistAuditLog(SysAuditLog auditLog) {
146	        try {
147	            auditLogRepository.save(auditLog);
148	        } catch (Exception ex) {
149	            log.warn("Failed to persist audit log for action={}", auditLog.getAction());
150	        }
151	    }
152	}
